import { Link } from "react-router-dom";
import authService from "src/auth/auth.service";
import { epochTogmt } from "src/utils/Common";
import { useState } from "react";

export const tableRemarksConstant = (businessQueryStatus, type) => {

    const [userData] = useState(authService.getUserDetailsFromLocalStorage())

    return [
        {
            id: 1,
            name: "Remarks",
            selector: (row) => row.remarks,
            sortable: true,
            reorder: true,
            width: '700px',
            wrap: true,
            //format: row => `${row.remarks.slice(0, 140)}...`,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 400,
            },
        },
        {
            id: 2,
            name: "Created Date",
            selector: (row) => epochTogmt(row.createTime),
            sortable: true,
            reorder: true,
            width: '150px',
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 3,
            name: "Remarked By",
            selector: (row) => row.remarkedBy,
            sortable: true,
            reorder: true,
            width: '200px',
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 4,
            name: "Last Updated By",
            selector: (row) => row.lastUpdatedBy,
            sortable: true,
            reorder: true,
            width: '200px',
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 5,
            name: "Action",
            width: '150px',
            cell: (row) => {
                return (
                    <>
                        {(userData?.email === "punam@wsegroup.in" || ((userData._id === row?.createrUserId) && row?.editExpireTime > new Date().getTime() && businessQueryStatus !== "CLOSED")) ? 
                            <Link className="btn" to={`/${type === "PAGE_QUERY" ? "user-view-query" : "business"}/remarks/edit/${row?._id}`} state={{businessQueryId: row.businessQueryId || row.pageQueryId, type: type}} style={{backgroundColor: '#03a680', color: '#ffffff', padding: '5px 12px', borderRadius: '30px'}}>
                                <i class="fa-regular fa-pen-to-square"></i>
                            </Link> :
                            null
                        }
                    </>
                );
            },
            sortable: true,
            reorder: true,
        },
        // {
        //     id: 5,
        //     name: "Status",
        //     cell: (row) => {
        //         return (
        //             <StatusDetails status={row.status} key={uuidv4()} />
        //         );
        //     },
        //     sortable: true,
        //     reorder: true,
        // },
        // {
        //     id: 6,
        //     name: "Action",
        //     cell: (row) => {
        //         return (
        //             <StatusDrop
        //                 id={row._id}
        //                 status={row.status}
        //                 type={'BUSINESS_REMARKS'}
        //                 action={fetchRemarksList}
        //                 key={uuidv4()}
        //                 publishPermission={"REMARKS_STATUS"}
        //             />
        //         );
        //     },
        //     sortable: true,
        //     reorder: true,
        // },
        // {
        //     id: 7,
        //     name: "Delete",
        //     cell: (row) => {
        //         return <i className={"fa-regular fa-trash-can" + (!authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row._id) }}></i>;
        //     },
        //     sortable: true,
        //     reorder: true,
        // },
    ];
};
